worked_example.final_code:
import java.util.*;

class Statistics<T extends Number & Comparable<T>> {
    private List<T> data = new ArrayList<>();

    public void add(T value)           { data.add(value); }
    public void addAll(List<T> values) { data.addAll(values); }
    public int count()                 { return data.size(); }

    public double sum() {
        double total = 0;
        for (T item : data) total += item.doubleValue();
        return total;
    }

    public double average() {
        return data.isEmpty() ? Double.NaN : sum() / count();
    }

    public T min() {
        if (data.isEmpty()) return null;
        T result = data.get(0);
        for (T item : data) if (item.compareTo(result) < 0) result = item;
        return result;
    }

    public T max() {
        if (data.isEmpty()) return null;
        T result = data.get(0);
        for (T item : data) if (item.compareTo(result) > 0) result = item;
        return result;
    }

    public double range()             { return max().doubleValue() - min().doubleValue(); }
    public boolean isBetween(T value) { return value.compareTo(min()) >= 0 && value.compareTo(max()) <= 0; }
}

public class StatsDemo {
    public static void main(String[] args) {
        Statistics<Integer> scores = new Statistics<>();
        scores.addAll(Arrays.asList(85, 92, 78, 95, 68, 88));
        System.out.println("Exam scores:");
        System.out.println("  Count: " + scores.count());
        System.out.println("  Average: " + scores.average());
        System.out.println("  Min: " + scores.min() + " | Max: " + scores.max());
        System.out.println("  Range: " + scores.range());
        System.out.println("  90 in range: " + scores.isBetween(90));

        Statistics<Double> prices = new Statistics<>();
        prices.addAll(Arrays.asList(2450.0, 3890.0, 1560.0, 412.0));
        System.out.println("\nStock prices:");
        System.out.println("  Average: ₹" + prices.average());
        System.out.println("  Range: ₹" + prices.range());
    }
}

